@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Components.Forms

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>Your privacy is important to us. This page outlines how we handle your data.</p>

<ul>
    <li>We collect only the data necessary to provide our services.</li>
    <li>We do not sell your personal information to third parties.</li>
    <li>You may request deletion of your data at any time.</li>
</ul>

<hr />

<h2>Cookie Consent</h2>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext.Request.Cookies.ContainsKey("consent");
    }
}

